def kamal_abbas_timeline():
    events = [
        {"year": 1989, "event": "Organized strike at steel plant in Helwan; arrested, tortured, and fired"},
        {"year": 2007, "event": "Charged with defamation; sentenced to one year in prison"},
        {"year": 2011, "event": "Played a key role in mobilizing workers during the Egyptian Revolution"},
        {"year": 2012, "event": "Sentenced to six months in prison for 'insulting' a public official"}
    ]
    return events

# Example usage
timeline = kamal_abbas_timeline()
for event in timeline:
    print(f"{event['year']}: {event['event']}")
